l_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":null,"original_start_line":null,"start_side":null,"line":229,"original_line":229,"side":"RIGHT","in_reply_to_id":1743840474,"original_position":80,"position":80,"subject_type":"line"},"pull_request":{"url":"https://api.github.com/repos/galaxyproject/galaxy/pulls/18760","id":2051184080,"node_id":"PR_kwDOAdw-Nc56QpXQ","html_url":"https://github.com/galaxyproject/galaxy/pull/18760","diff_url":"https://github.com/galaxyproject/galaxy/pull/18760.diff","patch_url":"https://github.com/galaxyproject/galaxy/pull/18760.patch","issue_url":"https://api.github.com/repos/galaxyproject/galaxy/issues/18760","number":18760,"state":"open","locked":false,"title":"Fix MSA viz, new dependency specification options.","user":{"login":"dannon","id":155398,"node_id":"MDQ6VXNlcjE1NTM5OA==","avatar_url":"https://avatars.githubusercontent.com/u/155398?v=4","gravatar_id":"","url":"https://api.github.com/users/dannon","html_url":"https://github.com/dannon","followers_url":"https://api.github.com/users/dannon/followers","following_url":"https://api.github.com/users/dannon/following{/other_user}","gists_url":"https://api.github.com/users/dannon/gists{/gist_id}","starred_url":"https://api.github.com/users/dannon/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/dannon/subscriptions","organizations_url":"https://api.github.com/users/dannon/orgs","repos_url":"https://api.github.com/users/dannon/repos","events_url":"https://api.github.com/users/dannon/events{/privacy}","received_events_url":"https://api.github.com/users/dannon/received_events","type":"User","site_admin":false},"body":"Primary driver was fixing the deployed MSA application on main -- this has been deployed to main in the usegalaxy branch as of last week and is working well to resolve our issues w/ msa.  Specifying node package dependencies and relying on prebuilt visualization plugins (as implemented here) is going to make a huge difference in reliability moving forward.

In short, visualizations should prebuild and publish a `static` directory with whatever they need to run.

In package.json, that's this new part:

```
    "files": [
        "static"
    ],
```

Then the viz is published to npm like so:  https://www.npmjs.com/@galaxyproject/msa

And then in the viz xml, we specify a particular version (or range, as appropriate) of plugin the viz is compatible with, like so:

```
    <requirements>
        <requirement type="package" version="0.2.1" package="@galaxyproject/msa"/>
    </requirements>
```

These requirements will all get staged to the Galaxy server's static file serving *without a build process required*, avoiding all of the issues we've had with differing node versions on novel and/or archaic systems.


